mapper.sql:
WHERE s.tenant_id = #{tenantId}
  AND s.del_flag = '0'

  AND (
    s.suite_code LIKE CONCAT('%', #{query.keyword}, '%')
    OR s.suite_name LIKE CONCAT('%', #{query.keyword}, '%')
    OR s.description LIKE CONCAT('%', #{query.keyword}, '%')
  )


  AND s.suite_code = #{query.suiteCode}


  AND s.status = #{query.status}

mapper.select:

WHERE s.tenant_id = #{tenantId}
  AND s.del_flag = '0'
  AND s.id = #{id}
LIMIT 1

SELECT

FROM ai_business_suite
WHERE tenant_id = #{tenantId}
  AND del_flag = '0'
  AND suite_code = #{suiteCode}
LIMIT 1

SELECT COUNT(1)
FROM ai_business_suite
WHERE tenant_id = #{tenantId}
  AND del_flag = '0'
  AND suite_code = #{suiteCode}

  AND id != #{excludeId}

SELECT COUNT(1)
FROM ai_business_object
WHERE tenant_id = #{tenantId}
  AND del_flag = '0'
  AND suite_code = #{suiteCode}

SELECT COUNT(1)
FROM ai_business_app
WHERE tenant_id = #{tenantId}
  AND del_flag = '0'
  AND suite_code = #{suiteCode}

SELECT COUNT(1)
FROM ai_business_suite
WHERE tenant_id = #{tenantId}
  AND del_flag = '0'
  AND parent_id = #{parentId}
